<?php namespace App\Services\Accounts; use App\Models\Accounts\AccountLedger; use App\Models\Accounts\Voucher; class LedgerService { public function createLedger($data) { return AccountLedger::create([...$data, 'created_by' => auth()->id()]); } public function createVoucher($ledgerId, $data) { $ledger = AccountLedger::findOrFail($ledgerId); if ($data['voucher_date'] > now()->toDateString() && !auth()->user()->hasPermission('override.backdating')) throw new \Exception('Backdating not allowed'); $voucher = Voucher::create([...$data, 'ledger_id' => $ledgerId, 'created_by' => auth()->id(), 'voucher_number' => 'V-'.now()->format('YmdHis')]); if ($data['type'] !== 'SALES_REVERSE') $ledger->increment('balance', $data['amount']); return $voucher; } }
